const item = $input.first();
const raw = item.json?.contractText ?? item.json?.text ?? item.json?.data ?? '';
const pages = item.json?.pages;
let fullText = raw;
if (Array.isArray(pages)) fullText = pages.map(p => p?.text ?? p).filter(Boolean).join('\n\n');
if (!fullText) {
  const found = Object.values(item.json).find(v => typeof v === 'string' && v.length > 100);
  if (found) fullText = found;
}

const config = $('Config').first()?.json ?? {};
const formData = item.json;
const contractText = String(fullText).slice(0, 12000);
const contractTextShort = contractText.substring(0, 4000);

return { json: {
  ...config,
  contractText,
  contractTextSafe: JSON.stringify(contractText).slice(1, -1),
  contractTextShortSafe: JSON.stringify(contractTextShort).slice(1, -1),
  charCount: String(fullText).length,
  filename: formData['Contract Name'] ?? formData.filename ?? 'contract.pdf',
  contract_type: formData['Contract Type'] ?? 'Other',
  counterparty: formData['Counterparty Name'] ?? '',
  submitter_name: formData['Your Name'] ?? '',
  submitter_email: formData['Your Email'] ?? '',
  department: formData['Department'] ?? ''
} };

const resp = $input.first().json;
const raw = resp.choices?.[0]?.message?.content ?? '{}';
let classification = {};
try {
  classification = JSON.parse(raw.replace(/```json?/g,'').replace(/```/g,'').trim());
} catch(e) {
  classification = { contract_type: 'Unknown', parties: [], jurisdiction: 'Unknown' };
}
const prev = $('Prepare Text').first()?.json ?? {};
return { json: { ...prev, classification } };

const resp = $input.first().json;
const raw = resp.choices?.[0]?.message?.content ?? '{}';
let analysis = {};
try {
  analysis = JSON.parse(raw.replace(/```json?/g,'').replace(/```/g,'').trim());
} catch(e) {
  analysis = { overall_risk_score: 50, risk_level: 'MEDIUM', executive_summary: 'AI parse error — manual review recommended', key_clauses: [], top_risks: ['Parse error'] };
}

const prev = $('Parse Classification').first()?.json ?? {};
const score = Math.min(100, Math.max(0, analysis.overall_risk_score ?? 50));
let riskLevel = analysis.risk_level ?? 'MEDIUM';
if (score >= 85) riskLevel = 'CRITICAL';
else if (score >= 70) riskLevel = 'HIGH';
else if (score >= 40) riskLevel = 'MEDIUM';
else riskLevel = 'LOW';

return { json: {
  ...prev,
  ...analysis,
  overall_risk_score: score,
  risk_level: riskLevel,
  key_clauses: analysis.key_clauses ?? [],
  top_risks: analysis.top_risks ?? [],
  missing_clauses: analysis.missing_clauses ?? [],
  obligations: analysis.obligations ?? [],
  negotiation_points: analysis.negotiation_points ?? [],
  compliance_flags: analysis.compliance_flags ?? [],
  raw_text_preview: (prev.contractText || '').slice(0, 500),
  status: score >= (prev.RISK_THRESHOLD ?? 70) ? 'flagged' : 'analyzed'
} };

const d = $input.first().json;
const score = d.overall_risk_score;
const level = d.risk_level;
const clauses = (d.key_clauses || []).slice(0, 5);
const topRisks = (d.top_risks || []).slice(0, 5);
const missing = (d.missing_clauses || []).slice(0, 3);
const negotiations = (d.negotiation_points || []).slice(0, 3);
const compliance = (d.compliance_flags || []).slice(0, 3);

const emoji = level === 'CRITICAL' ? '🔴' : level === 'HIGH' ? '🟠' : level === 'MEDIUM' ? '🟡' : '🟢';
const color = level === 'CRITICAL' ? '#dc2626' : level === 'HIGH' ? '#ea580c' : level === 'MEDIUM' ? '#ca8a04' : '#16a34a';

const slackBlocks = [
  { type: 'header', text: { type: 'plain_text', text: `${emoji} Contract Analysis: ${d.filename}` } },
  { type: 'section', text: { type: 'mrkdwn', text: `*Risk Score:* ${score}/100 — *${level}*\n*Type:* ${d.classification?.contract_type ?? d.contract_type ?? 'N/A'} | *Jurisdiction:* ${d.classification?.jurisdiction ?? 'N/A'}\n*Parties:* ${(d.classification?.parties ?? []).map(p => `${p.name} (${p.role})`).join(', ') || 'N/A'}\n*Counterparty:* ${d.counterparty || 'N/A'} | *Submitted by:* ${d.submitter_name || 'N/A'} (${d.department || 'N/A'})` } },
  { type: 'divider' },
  { type: 'section', text: { type: 'mrkdwn', text: `*Executive Summary*\n${d.executive_summary || 'N/A'}` } }
];

if (topRisks.length > 0) {
  slackBlocks.push({ type: 'section', text: { type: 'mrkdwn', text: `*Top Risks*\n${topRisks.map((r, i) => `${i+1}. ${r}`).join('\n')}` } });
}
if (clauses.length > 0) {
  slackBlocks.push({ type: 'section', text: { type: 'mrkdwn', text: `*Key Clauses*\n${clauses.map(c => `• *${c.clause_type}* [${(c.risk_level || '').toUpperCase()}]: ${c.risk_explanation || c.excerpt || ''}`).join('\n')}` } });
}
if (missing.length > 0) {
  slackBlocks.push({ type: 'section', text: { type: 'mrkdwn', text: `*Missing Clauses*\n${missing.map(m => `⚠️ ${m}`).join('\n')}` } });
}
if (negotiations.length > 0) {
  slackBlocks.push({ type: 'section', text: { type: 'mrkdwn', text: `*Negotiation Points*\n${negotiations.map(n => `💡 ${n}`).join('\n')}` } });
}

slackBlocks.push({ type: 'context', elements: [{ type: 'mrkdwn', text: `Analyzed at ${new Date().toISOString()} | Contract Intelligence Pro` }] });

const clauseRows = clauses.map(c => {
  const bg = c.risk_level === 'critical' ? '#fecaca' : c.risk_level === 'high' ? '#fed7aa' : c.risk_level === 'medium' ? '#fef08a' : '#bbf7d0';
  return `<tr style="background:${bg}"><td style="padding:8px;border:1px solid #e5e7eb">${c.clause_type}</td><td style="padding:8px;border:1px solid #e5e7eb">${(c.risk_level||'').toUpperCase()}</td><td style="padding:8px;border:1px solid #e5e7eb">${c.risk_explanation || ''}</td><td style="padding:8px;border:1px solid #e5e7eb">${c.recommendation || ''}</td></tr>`;
}).join('');

const emailHtml = `
<div style="font-family:Arial,sans-serif;max-width:700px;margin:0 auto">
  <div style="background:${color};color:white;padding:20px;border-radius:8px 8px 0 0">
    <h1 style="margin:0;font-size:22px">${emoji} Contract Analysis Report</h1>
    <p style="margin:8px 0 0;font-size:16px">${d.filename} — Risk Score: ${score}/100 (${level})</p>
  </div>
  <div style="padding:20px;background:#f9fafb;border:1px solid #e5e7eb">
    <table style="width:100%;border-collapse:collapse;margin-bottom:16px">
      <tr><td style="padding:6px 12px;font-weight:bold;width:140px">Contract Type</td><td style="padding:6px 12px">${d.classification?.contract_type ?? d.contract_type ?? 'N/A'}</td></tr>
      <tr><td style="padding:6px 12px;font-weight:bold">Counterparty</td><td style="padding:6px 12px">${d.counterparty || 'N/A'}</td></tr>
      <tr><td style="padding:6px 12px;font-weight:bold">Jurisdiction</td><td style="padding:6px 12px">${d.classification?.jurisdiction ?? 'N/A'}</td></tr>
      <tr><td style="padding:6px 12px;font-weight:bold">Submitted by</td><td style="padding:6px 12px">${d.submitter_name || 'N/A'} (${d.department || 'N/A'})</td></tr>
      <tr><td style="padding:6px 12px;font-weight:bold">Parties</td><td style="padding:6px 12px">${(d.classification?.parties ?? []).map(p => `${p.name} (${p.role})`).join(', ') || 'N/A'}</td></tr>
    </table>
    <h2 style="color:#1f2937;font-size:16px;margin:16px 0 8px">Executive Summary</h2>
    <p style="color:#4b5563;line-height:1.6">${d.executive_summary || 'N/A'}</p>
    ${topRisks.length > 0 ? `<h2 style="color:#1f2937;font-size:16px;margin:16px 0 8px">Top Risks</h2><ul style="color:#4b5563">${topRisks.map(r => `<li>${r}</li>`).join('')}</ul>` : ''}
    ${clauses.length > 0 ? `<h2 style="color:#1f2937;font-size:16px;margin:16px 0 8px">Key Clauses</h2><table style="width:100%;border-collapse:collapse"><tr style="background:#f3f4f6"><th style="padding:8px;border:1px solid #e5e7eb;text-align:left">Clause</th><th style="padding:8px;border:1px solid #e5e7eb;text-align:left">Risk</th><th style="padding:8px;border:1px solid #e5e7eb;text-align:left">Explanation</th><th style="padding:8px;border:1px solid #e5e7eb;text-align:left">Recommendation</th></tr>${clauseRows}</table>` : ''}
    ${missing.length > 0 ? `<h2 style="color:#1f2937;font-size:16px;margin:16px 0 8px">Missing Clauses</h2><ul style="color:#dc2626">${missing.map(m => `<li>${m}</li>`).join('')}</ul>` : ''}
    ${negotiations.length > 0 ? `<h2 style="color:#1f2937;font-size:16px;margin:16px 0 8px">Negotiation Points</h2><ul style="color:#2563eb">${negotiations.map(n => `<li>${n}</li>`).join('')}</ul>` : ''}
    ${compliance.length > 0 ? `<h2 style="color:#1f2937;font-size:16px;margin:16px 0 8px">Compliance Flags</h2><ul style="color:#9333ea">${compliance.map(c => `<li>${c}</li>`).join('')}</ul>` : ''}
  </div>
  <div style="padding:12px 20px;background:#f3f4f6;border-radius:0 0 8px 8px;text-align:center;color:#9ca3af;font-size:12px">
    Contract Intelligence Pro — Analyzed ${new Date().toISOString().split('T')[0]}
  </div>
</div>`;

return { json: { ...d, slackBlocks: JSON.stringify(slackBlocks), emailHtml, emailSubject: `${emoji} [${level}] Contract Analysis: ${d.filename} — Score ${score}/100` } };

