={
  "model": "{{ $json.AI_MODEL ?? 'gpt-4o-mini' }}",
  "response_format": { "type": "json_object" },
  "messages": [
    {
      "role": "system",
      "content": "You are a legal document classifier. Extract metadata from the contract. Reply ONLY with valid JSON. Language: {{ $json.CONTRACT_LANG ?? 'en' }}."
    },
    {
      "role": "user",
      "content": "Classify this contract and return JSON with EXACTLY these fields: { \"contract_type\": \"NDA|MSA|SOW|Employment|SaaS|Consulting|Partnership|Other\", \"parties\": [{\"name\": string, \"role\": \"client|vendor|employer|employee|partner|other\"}], \"effective_date\": \"ISO date or unknown\", \"expiration_date\": \"ISO date or unknown\", \"auto_renewal\": boolean, \"jurisdiction\": \"country/region\", \"governing_law\": string, \"language\": string, \"estimated_value\": \"amount or unknown\" }. Submitted as: {{ $json.contract_type }}. Counterparty: {{ $json.counterparty }}."
    },
    {
      "role": "user",
      "content": "{{ $json.contractTextShortSafe }}"
    }
  ],
  "temperature": 0.1,
  "max_tokens": 500
}

